Map<String, String> getDailyQuote(String category) {
  final list = kQuotesByCategory[category] ?? kQuotesByCategory['default']!;
  final now = DateTime.now();
  final idx = (now.year * 1000 + now.month * 31 + now.day) % list.length;
  return list[idx];
}
